// Internal-call entry point. Triggered by MCP generate_video, by birthday
// cron, by lead-capture welcome trigger, or any other workflow that needs
// a personalised video sent. Validates the internal secret + required
// fields, defaults intent to 'general' so a missing template still works.
const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) {
  return { json: { _unauthorized: true, status: 401, error: 'internal_secret required' } };
}
if (!body.lead_id) return { json: { _empty: true, status: 400, error: 'lead_id required' } };
if (!body.client_id) return { json: { _empty: true, status: 400, error: 'client_id required' } };

const allowedIntents = ['general','welcome','birthday','anniversary','review_request','financial_tip','referral_request','quote_followup','booking_followup'];
const intent = allowedIntents.indexOf(body.intent) !== -1 ? body.intent : 'general';

return { json: {
  _authorized: true,
  lead_id: body.lead_id,
  client_id: body.client_id,
  intent: intent,
  override_script: body.override_script || null,
  delivery_channel: body.delivery_channel || 'auto'
} };

// to a non-existent row.
const resp = $input.item.json || {};
const data = resp.data || resp;
const videoRenderId = data && (data.video_render_id || (data.row && data.row.id) || data.id) || null;
if (!videoRenderId) {
  return { json: { _failed: true, status: 502, error: 'script-generator returned no video_render_id', upstream: resp } };
}
const orig = $('Validate').item.json;
return { json: {
  video_render_id: videoRenderId,
  lead_id: orig.lead_id,
  client_id: orig.client_id,
  intent: orig.intent,
  delivery_channel: orig.delivery_channel
} };

// Build success response. The actual video isn't ready yet — HeyGen
// processes async (5-30 min) and calls clx-heygen-webhook-v1 when done,
// which then routes through clx-video-delivery-router-v1 to the lead.
const ext = $('Extract Render Id').item.json;
const heygenResp = $input.item.json || {};
const heygenOk = heygenResp && (heygenResp.ok !== false) && !heygenResp.error;
return { json: {
  ok: true,
  video_render_id: ext.video_render_id,
  lead_id: ext.lead_id,
  client_id: ext.client_id,
  intent: ext.intent,
  status: heygenOk ? 'rendering' : 'render_kickoff_failed',
  heygen_response: heygenResp,
  message: heygenOk
    ? 'Video script generated, HeyGen render started. Delivery routes automatically on callback (5-30 min).'
    : 'Script generated but HeyGen kickoff failed. Check render workflow logs.'
} };
